var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"어제도 숙소에 외교부 이름으로 귀국 요청이 왔던데요.","JPN":"昨日も宿に外交省から帰国要請が届いてました。","ENG":"I saw that the Ministry of Foreign Affairs sent another request for my return to my dorm yesterday.","TWN":"我昨天也有收到外交部署名送來的回國通知。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"하여튼 이용할 구석이 남아 있으면 끝까지 포기하질 않는다니까요.","JPN":"まったく、利用できると思ったらとことん諦めないんですから。","ENG":"Ugh. They won't let me go as long as I have some use for them.","TWN":"只要你還有利用的價值，他們就會糾纏到底。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"넷튜브에 이상한 영상들을 올리는 바람에 외출도 못 할 정도라고요.","JPN":"ネットチューブに怪しい動画がアップロードされているせいで外出もままならないくらいです。","ENG":"I can't even go out because of all the weird videos being uploaded on NetTube.","TWN":"因為在平台上流傳的奇怪影片，害我現在都無法出門。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"어차피 탐내는 건 제가 아니라 이 장비겠지만….","JPN":"欲しいのは私ではなくて、この装備でしょうが……","ENG":"But I bet that they're just after my gear and not me...","TWN":"我知道他們想要的不是我，而是這件裝備…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"계속 뻗대다간 길거리에서 국가의 배신자라고 암살당할지도요.","JPN":"このまま突っぱね続けたら、道端で国家反逆者として暗殺されるかもしれません。","ENG":"If I keep refusing, I might be branded as a traitor and get assassinated out on the streets.","TWN":"要是我再堅持下，說不定會被當成是叛國賊用石頭砸死……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"농담이면 좋겠는데, 우리나라에서는 충분히 벌어질 수 있는 일이라서요.","JPN":"冗談になればいいのですが、この国では十分にあり得ることですからね。","ENG":"I wish I was joking. But it's something that can really happen in my country.","TWN":"我也希望是開玩笑，但這種事在我們國家是很有可能發生的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"이러다간 타의로 돌아가야 할지도 모르겠어요. 후으….","JPN":"自分の意志とは関係なく、帰らなくちゃならなくなるかもしれません。ふう……","ENG":"At this rate, I might have to go back just because of the pressure. Hngh...","TWN":"我看我只能被迫回國囉，哀哀……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"그러지 않아도 된다구요?","JPN":"そうする必要はないって？","ENG":"I don't have to?","TWN":"不用嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"으음…. 딱히 싫다는 건 아닌데요.","JPN":"う～ん……別に嫌だというわけではないんですが。","ENG":"Hmm... it's not that I don't want to.","TWN":"嗯…我不是不願意。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"그래도 명색이 국가인데, 사장님 혼자서는 부담스럽지 않나요?","JPN":"仮にも国家ですから、社長お一人では荷が重くないですか？","ENG":"I mean, it's still a country. Won't it be hard for you to stop them on your own?","TWN":"只是對方可是一個國家，憑老闆一個人，會不會壓力太大？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"그로니아가 나라 취급 받기 어렵다는 건 잘 알지만요.","JPN":"グロニアが国として見られないことはよくわかっていますが。","ENG":"Of course, Gronia is not really recognized as a nation globally...","TWN":"我也知道格羅尼亞在國際上可能稱不上國家。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"괜히 나서시다가 다치면 다른 직원 분들한테 저만 혼난다구요.","JPN":"解決しようとして社長が怪我でもされたら、他の社員の方に私が怒られますからね。","ENG":"But if you go out of your way to help and get hurt, I'll be the one the other employees will scold.","TWN":"但萬一你因為我出什麼差錯，其他員工一定會怪我的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"……펴, 평생 책임져 주겠다뇨. 무슨 소리예요?","JPN":"……い、一生責任を持つって。何を言ってるんですか？","ENG":"Y-you'll take care of me forever? What's that supposed to mean?","TWN":"你…你對我負一輩子的責任？這是什麼意思？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"아… 그 호출할 때 말씀하셨던 계약 건 말이죠.","JPN":"ああ……呼ばれた時に言われていた契約の件でしたか。","ENG":"Oh... You're talking about that contract you mentioned before.","TWN":"喔…就你是說之前提過的契約喔。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"아하하…. 네. 이해했어요.","JPN":"あはは……はい。理解しました。","ENG":"Ah hah hah... Yes, I understand.","TWN":"哈哈哈……明白，明白。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"뭐, 계속 추켜세워 주니까 저도 모르게 어깨에 힘이 좀 들어갔나 보네요. 엉뚱한 착각이나 하고.","JPN":"社長がいつもおだててくれるので、我知らずいい気になっていたみたいです。見当違いのこと言っちゃいました。","ENG":"Well, I guess all the praise has made me a little cocky. Having these stupid thoughts and all.","TWN":"因為周圍的人一直捧我，害我可能也有點得意忘形，才會誤會你的意思。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"그러면, 계약서는 따로 확인할 필요 없는 거죠? 사장님.","JPN":"では、契約書は特に確認しなくてもいいですよね？　社長。","ENG":"Then, I don't have to check the contract, do I, Boss?","TWN":"那老闆，應該不需要再確認契約內容吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};